int printf(const char *, ...);
int a, b, e, g;
volatile int c;
static int d[1] = {1}, f;
int h() {
  for (b = 0; b < 4; b++) {
    for (e = 0; e < 4; e++)
      while (b) {
        if (c > 0 && d[1])
          break;
        return f;
      }
  }
  return 0;
}
void i() {
  int *j[1];
  j[g] = &d[0];
}
int main() {
  h();
  printf("%d\n", a);
  return 0;
